mapper.select:
SELECT userTeam.team_name,checkItemsTask.user_name, sum( userProportion.user_proportion * checkDuration.duration ) AS work_hour FROM test_check_items_task_rel checkItemsTask INNER JOIN ( SELECT checkItem.task_id,checkItem.check_item_id,productItem.duration FROM ( SELECT checkItemRecord.task_id, checkItemRecord.check_item_id FROM test_entrusted_sample_checkitem_rel checkItemRecord WHERE checkItemRecord.end_time IS NOT NULL
AND DATE_FORMAT(checkItemRecord.end_time, '%Y-%m-%d') >= DATE_FORMAT(#{map.beginTime}, '%Y-%m-%d')
AND DATE_FORMAT(checkItemRecord.end_time, '%Y-%m-%d') <= DATE_FORMAT(#{map.endTime}, '%Y-%m-%d')
) checkItem INNER JOIN test_product_item productItem ON checkItem.check_item_id = productItem.check_item_id ) checkDuration ON checkItemsTask.task_id = checkDuration.task_id AND checkItemsTask.item_id = checkDuration.check_item_id INNER JOIN test_user_proportion userProportion ON checkItemsTask.user_type = userProportion.user_type INNER JOIN ( SELECT technicist.user_id, team.NAME AS team_name FROM test_technicist technicist INNER JOIN test_team team ON technicist.team_id = team.id
and team.id in
#{id}
) userTeam ON checkItemsTask.user_id = userTeam.user_id
AND checkItemsTask.user_name LIKE concat(concat('%',#{map.userName}),'%')
GROUP BY checkItemsTask.user_id

SELECT t1.id as taskId, t1.order_time, t1.required_completion_time, t1.task_code, t2.NAME AS receiver, "任务大厅" AS source, t3.id as state FROM test_task AS t1 LEFT JOIN sys_user AS t2 ON t1.receiver = t2.user_id LEFT JOIN test_task_order_working_hours AS t3 ON t1.id = t3.task_id
1=1
and t1.receiver = #{receiverUserId}
AND t1.order_time >= #{startDate}
AND #{stopDate} >= t1.required_completion_time

SELECT sum( t2.times * t3.report_model_id ) FROM test_task AS t1 LEFT JOIN test_entrusted_sample_checkitem_rel AS t2 ON t1.id = t2.task_id LEFT JOIN test_product_item AS t3 ON t2.check_item_id = t3.check_item_id
1=1
and t1.receiver = #{receiverUserId}
